11→export const getEnvFile = (): string => {
12→	if (isTestEnv()) return '.env.test';
13→	return '.env';
14→};
15→
16→export const getEnvVariables = (): Record<string, string | number | undefined> => ({
17→	NODE_ENV: process.env['NODE_ENV'],
18→	PORT: process.env['PORT'],
19→	GLOBAL_PREFIX: process.env['GLOBAL_PREFIX'],
20→	SERVER_NAME: process.env['SERVER_NAME'],
21→	IS_COMPACT_LOGS: process.env['IS_COMPACT_LOGS'],
22→	IS_JSON_LIKE_LOGS: process.env['IS_JSON_LIKE_LOGS'],
23→	GRACEFUL_SHUTDOWN_DELAY: process.env['GRACEFUL_SHUTDOWN_DELAY'],
24→});
25→
26→export const loadEnvVariables = (): ConfigFactory[] => {
27→	if (isStagingEnv() || isProdEnv()) {
28→		validate({ envConfig: getEnvVariables() });
29→		return [getEnvVariables];
30→	}
31→
32→	const envFilePath = path.resolve(process.cwd(), getEnvFile());
33→
34→	if (!fs.existsSync(envFilePath)) {
35→		if (isDevEnv()) {
36→			throw new Error(`Env file not found: ${envFilePath}`);
37→		}
38→		return [() => ({})];
39→	}
40→
41→	const envConfig = dotenv.parse(fs.readFileSync(envFilePath));
42→
43→	validate({ envConfig });
44→
45→	return [() => envConfig];
